import React from 'react';
import { Card, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

const conditionToEmoji = (condition: string): string => {
  const normalized = condition.toLowerCase();
  if (normalized.includes('sun')) return '☀️';
  if (normalized.includes('cloud')) return '☁️';
  if (normalized.includes('rain') || normalized.includes('drizzle')) return '🌧️';
  if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
  if (normalized.includes('snow') || normalized.includes('sleet')) return '❄️';
  if (normalized.includes('wind')) return '🌬️';
  if (normalized.includes('fog') || normalized.includes('mist') || normalized.includes('haze')) return '🌫️';
  return '🌤️';
};

export default function GeneratedComponent({
  city = 'City',
  temperature = 0,
  condition = 'Clear',
  humidity = 0,
  windSpeed = 0,
  unit = 'C',
  forecast = [],
}: Props) {
  const unitLabel = unit || 'C';
  const currentIcon = conditionToEmoji(condition);

  return (
    <Card
      padding="var(--ggui-spacing-6, 24px)"
      shadow="md"
      radius="xl"
      border
      aria-label={`Weather card for ${city}`}
    >
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Text
          variant="label"
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
          aria-label="City name"
        >
          {city}
        </Text>

        <Stack direction="horizontal" justify="between" align="center">
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Text
              size="4xl"
              weight="bold"
              color="var(--ggui-color-onSurface, #18181b)"
              aria-label={`Current temperature ${temperature} degrees ${unitLabel}`}
            >
              {temperature}°{unitLabel}
            </Text>
            <Text
              variant="bodyLarge"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              aria-label={`Weather condition ${condition}`}
            >
              {condition}
            </Text>
          </Stack>

          <Text
            as="span"
            size="4xl"
            aria-label={`Condition icon ${currentIcon}`}
            color="var(--ggui-color-onSurface, #18181b)"
          >
            {currentIcon}
          </Text>
        </Stack>

        <Stack
          direction="horizontal"
          justify="between"
          gap="var(--ggui-spacing-4, 16px)"
          wrap
          aria-label="Weather metrics"
        >
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Humidity
            </Text>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              {humidity}%
            </Text>
          </Stack>

          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Wind
            </Text>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              {windSpeed} km/h
            </Text>
          </Stack>
        </Stack>

        <Stack
          direction="horizontal"
          gap="var(--ggui-spacing-2, 8px)"
          wrap
          aria-label="5-day forecast"
        >
          {forecast.map((item, index) => (
            <Card
              key={`${item.day ?? 'day'}-${index}`}
              padding="var(--ggui-spacing-2, 8px)"
              radius="md"
              shadow="none"
              border
            >
              <Stack align="center" gap="var(--ggui-spacing-1, 4px)">
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  truncate
                >
                  {item.day ?? '—'}
                </Text>
                <Text
                  as="span"
                  size="lg"
                  aria-label={`${item.day ?? 'Day'} icon ${item.icon ?? '🌤️'}`}
                  color="var(--ggui-color-onSurface, #18181b)"
                >
                  {item.icon ?? '🌤️'}
                </Text>
                <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)">
                  {item.high ?? '—'}° / {item.low ?? '—'}°
                </Text>
              </Stack>
            </Card>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Text, Heading, Box, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast,
}: Props) {
  const normalizedCondition = condition.toLowerCase();

  const getConditionIcon = (value: string): string => {
    const normalized = value.toLowerCase();
    if (normalized.includes('thunder') || normalized.includes('storm')) return '⛈️';
    if (normalized.includes('snow')) return '❄️';
    if (normalized.includes('rain') || normalized.includes('drizzle') || normalized.includes('shower')) return '🌧️';
    if (normalized.includes('partly') && normalized.includes('cloud')) return '⛅';
    if (normalized.includes('cloud') || normalized.includes('overcast')) return '☁️';
    if (normalized.includes('fog') || normalized.includes('mist') || normalized.includes('haze')) return '🌫️';
    if (normalized.includes('wind')) return '💨';
    if (normalized.includes('clear') || normalized.includes('sun')) return '☀️';
    return '🌤️';
  };

  const currentIcon = getConditionIcon(normalizedCondition);

  return (
    <Card
      shadow="md"
      radius="xl"
      border
      padding="var(--ggui-spacing-6, 24px)"
      aria-label={`Weather for ${city}`}
    >
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Stack gap="var(--ggui-spacing-2, 8px)">
          <Heading
            level={4}
            color="var(--ggui-color-onSurface, #18181b)"
            align="left"
          >
            {city}
          </Heading>

          <Stack direction="horizontal" justify="between" align="center" wrap>
            <Stack gap="var(--ggui-spacing-2, 8px)">
              <Text
                variant="body"
                size="4xl"
                weight="bold"
                color="var(--ggui-color-onSurface, #18181b)"
                as="div"
              >
                {temperature}°{unit}
              </Text>
              <Text
                variant="bodyLarge"
                weight="medium"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
                truncate
              >
                {condition}
              </Text>
            </Stack>

            <Box
              padding="var(--ggui-spacing-2, 8px)"
              background="var(--ggui-color-surface, #fafafa)"
              borderRadius="var(--ggui-shape-radius-lg, 12px)"
            >
              <Text
                as="span"
                size="4xl"
                color="var(--ggui-color-onSurface, #18181b)"
                aria-hidden="true"
              >
                {currentIcon}
              </Text>
            </Box>
          </Stack>
        </Stack>

        <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap>
          <Box
            padding="var(--ggui-spacing-2, 8px)"
            background="var(--ggui-color-surface, #fafafa)"
            borderRadius="var(--ggui-shape-radius-md, 8px)"
          >
            <Stack gap="var(--ggui-spacing-1, 4px)">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Humidity
              </Text>
              <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                {humidity}%
              </Text>
            </Stack>
          </Box>

          <Box
            padding="var(--ggui-spacing-2, 8px)"
            background="var(--ggui-color-surface, #fafafa)"
            borderRadius="var(--ggui-shape-radius-md, 8px)"
          >
            <Stack gap="var(--ggui-spacing-1, 4px)">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Wind speed
              </Text>
              <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                {windSpeed}
              </Text>
            </Stack>
          </Box>
        </Stack>

        <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        <Stack gap="var(--ggui-spacing-2, 8px)" aria-label="5-day forecast">
          <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Forecast
          </Text>

          <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" justify="between" wrap={false}>
            {forecast.map((item, index) => {
              const day = item.day ?? '—';
              const icon = item.icon ?? currentIcon;
              const high = item.high !== undefined ? `${item.high}°${unit}` : '—';
              const low = item.low !== undefined ? `${item.low}°${unit}` : '—';

              return (
                <Box
                  key={`${item.day ?? 'day'}-${index}`}
                  padding="var(--ggui-spacing-2, 8px)"
                  background="var(--ggui-color-surface, #fafafa)"
                  borderRadius="var(--ggui-shape-radius-lg, 12px)"
                  style={{
                    flex: 1,
                    minWidth: '0',
                    border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-1, 4px)" align="center">
                    <Text
                      variant="label"
                      color="var(--ggui-color-onSurface, #18181b)"
                      truncate
                      align="center"
                    >
                      {day}
                    </Text>
                    <Text size="2xl" as="span" aria-hidden="true">
                      {icon}
                    </Text>
                    <Stack gap={2} align="center">
                      <Text
                        variant="bodySmall"
                        weight="semibold"
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        {high}
                      </Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {low}
                      </Text>
                    </Stack>
                  </Stack>
                </Box>
              );
            })}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}

import React from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Divider,
  Box
} from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * WeatherCard Component
 * Displays current weather information and a 5-day forecast strip.
 * Designed for visual hierarchy and theme-agnostic presentation.
 */
export default function WeatherCard({
  city = "Tokyo",
  temperature = 28,
  condition = "Sunny",
  humidity = 45,
  windSpeed = 8,
  unit = "C",
  forecast = []
}: Props) {
  // Helper to map text condition to a representative emoji
  const getWeatherEmoji = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain') || c.includes('drizzle')) return '🌧️';
    if (c.includes('storm') || c.includes('thunder')) return '⛈️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('mist') || c.includes('fog')) return '🌫️';
    return '⛅';
  };

  return (
    <Card 
      padding={24} 
      radius="xl" 
      shadow="md" 
      border={false}
      style={{
        background: 'var(--ggui-color-surface, #ffffff)',
        maxWidth: '400px',
        width: '100%',
        color: 'var(--ggui-color-onSurface, #18181b)'
      }}
    >
      <Stack gap={24}>
        {/* Header: City and Condition Label */}
        <Stack gap={4}>
          <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
            {city}
          </Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {condition}
          </Text>
        </Stack>

        {/* Hero Temperature Display */}
        <Stack direction="horizontal" align="center" justify="between">
          <Text 
            size="4xl" 
            weight="bold" 
            color="var(--ggui-color-onSurface, #18181b)"
            style={{ 
              fontSize: 'var(--ggui-font-size-4xl, 64px)',
              lineHeight: 1 
            }}
          >
            {temperature}°{unit}
          </Text>
          <Text style={{ fontSize: '64px', lineHeight: 1 }}>
            {getWeatherEmoji(condition)}
          </Text>
        </Stack>

        {/* Environmental Metadata */}
        <Stack direction="horizontal" gap={12} wrap>
          <Box 
            paddingX={12} 
            paddingY={8} 
            background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
            borderRadius="var(--ggui-shape-radius-md, 8px)"
            style={{ flex: 1, minWidth: '120px' }}
          >
            <Stack gap={2} align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
              <Text variant="label" weight="semibold">{humidity}%</Text>
            </Stack>
          </Box>
          <Box 
            paddingX={12} 
            paddingY={8} 
            background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
            borderRadius="var(--ggui-shape-radius-md, 8px)"
            style={{ flex: 1, minWidth: '120px' }}
          >
            <Stack gap={2} align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind Speed</Text>
              <Text variant="label" weight="semibold">{windSpeed} km/h</Text>
            </Stack>
          </Box>
        </Stack>

        <Divider margin={8} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        {/* Forecast Strip */}
        <Stack direction="horizontal" justify="between" align="center" gap={12} style={{ overflowX: 'auto', paddingBottom: '4px' }}>
          {forecast.map((item, index) => (
            <Stack 
              key={`${item.day}-${index}`} 
              gap={8} 
              align="center" 
              style={{ flexShrink: 0, minWidth: '60px' }}
            >
              <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {item.day}
              </Text>
              <Text style={{ fontSize: '24px' }}>
                {item.icon}
              </Text>
              <Stack gap={0} align="center">
                <Text variant="label" weight="bold" size="sm" color="var(--ggui-color-onSurface, #18181b)">
                  {item.high}°
                </Text>
                <Text variant="caption" size="xs" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.low}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Text, Heading, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * WeatherCard component for displaying real-time weather data and 5-day forecast.
 */
export default function WeatherCard({
  city = "Tokyo",
  temperature = 28,
  condition = "Sunny",
  humidity = 45,
  windSpeed = 8,
  unit = "C",
  forecast = [
    { day: "Mon", icon: "☀️", high: 30, low: 22 },
    { day: "Tue", icon: "⛅", high: 27, low: 20 },
    { day: "Wed", icon: "☁️", high: 25, low: 18 },
    { day: "Thu", icon: "🌧️", high: 22, low: 17 },
    { day: "Fri", icon: "🌤️", high: 26, low: 19 }
