}: Props) {
  return (
    <Card padding="var(--ggui-spacing-6, 24px)" radius="xl" shadow="md" style={{ width: '100%', maxWidth: '400px' }}>
      <Stack gap="var(--ggui-spacing-6, 24px)">
        {/* Header: City and Condition */}
