        <Stack direction="horizontal" align="center" justify="between" wrap>
          {/* Prominent Temperature Display */}
          <Stack direction="horizontal" align="start" gap="var(--ggui-spacing-1, 4px)">
            <Text
              size="4xl"
              weight="bold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {Math.round(temperature)}
            </Text>
            <Text
              size="2xl"
              weight="semibold"
              color="var(--ggui-color-primary-600, #0284c7)"
              style={{ marginTop: 'var(--ggui-spacing-2, 8px)' }}
