        >
          <Stack direction="horizontal" justify="between" align="center" wrap gap="var(--ggui-spacing-3, 12px)">
            {forecast.map((item, index) => (
              <Stack key={item.day || index} align="center" gap="var(--ggui-spacing-1, 4px)" style={{ flex: '1 1 0px', minWidth: '50px' }}>
                <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.day}
                </Text>
                <Text size="xl" aria-hidden="true" style={{ margin: 'var(--ggui-spacing-1, 4px) 0' }}>
                  {item.icon}
                </Text>
                <Stack direction="horizontal" gap="var(--ggui-spacing-1, 4px)" justify="center">
                  <Text weight="semibold" size="xs" color="var(--ggui-color-onSurface, #18181b)">
                    {item.high}°
                  </Text>
                  <Text size="xs" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {item.low}°
                  </Text>
                </Stack>
              </Stack>
            ))}
          </Stack>
        </Box>
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Text, Heading, Divider } from '@ggui-ai/design/primitives';

interface ForecastItem {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
}

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: ForecastItem[];
}

/**
 * WeatherCard Component
 * Displays current weather data and a 5-day forecast.
 */
export default function WeatherCard({
  city = 'Unknown City',
  temperature = 0,
  condition = 'Unknown',
  humidity = 0,
  windSpeed = 0,
  unit = 'C',
  forecast = [],
}: Props) {
  // Helper to map condition string to an emoji
  const getConditionEmoji = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain') || c.includes('drizzle')) return '🌧️';
    if (c.includes('thunder') || c.includes('storm')) return '⛈️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('mist') || c.includes('fog')) return '🌫️';
    return '⛅';
  };

  return (
    <Card
      shadow="md"
      radius="lg"
      padding={24}
      border={true}
      aria-label={`Weather in ${city}, ${condition}, ${temperature} degrees ${unit}`}
    >
      <Stack direction="vertical" gap={24}>
        {/* Top Section: Location & Condition */}
        <Stack align="center" gap={4}>
          <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
            {city}
          </Heading>
          <Text
            variant="bodyLarge"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            {condition}
          </Text>
        </Stack>

        {/* Middle Section: Current Data */}
        <Stack align="center" gap={16}>
          {/* Main Temperature and Icon */}
          <Stack direction="horizontal" align="center" justify="center" gap={16}>
            <Text 
              size="4xl" 
              as="span" 
              style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)', transform: 'scale(1.5)', display: 'inline-block' }}
            >
              {getConditionEmoji(condition)}
            </Text>
            <Text
              size="4xl"
              weight="bold"
              color="var(--ggui-color-onSurface, #18181b)"
              style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)', transform: 'scale(1.8)', margin: '0 16px' }}
            >
              {temperature}°{unit}
            </Text>
          </Stack>

          {/* Details Row (Humidity & Wind) */}
          <Stack direction="horizontal" justify="center" gap={32}>
            <Stack align="center" gap={4}>
              <Text
                variant="label"
                size="xs"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
                style={{ textTransform: 'uppercase', letterSpacing: 'var(--ggui-spacing-1, 4px) / 10' }}
              >
                Humidity
              </Text>
              <Text
                variant="body"
                weight="medium"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {humidity}%
              </Text>
