import React from 'react';
import {
  Card,
  Stack,
  Heading,
  Text,
  Divider,
  Box,
} from '@ggui-ai/design/primitives';

interface ForecastItem {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
}

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast,
}: Props) {
  return (
    <Card shadow="md" padding={24} radius="lg" border={true}>
      <Stack direction="vertical" gap={16}>
        {/* HEADER: City + Condition + Temperature */}
        <Stack direction="horizontal" gap={24} align="start">
          {/* City Name */}
          <Heading level={3} color="var(--ggui-color-onSurface, #111827)">
            {city}
          </Heading>

          {/* Condition + Temperature */}
          <Stack direction="vertical" gap={4}>
            {/* Condition with Icon */}
            <Stack direction="horizontal" gap={8} align="center">
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #374151)">
                {condition}
              </Text>
              <Text size="2xl" color="currentColor">
                {condition === 'Sunny' && '☀️'}
                {condition === 'Cloudy' && '☁️'}
                {condition === 'Rainy' && '🌧️'}
                {condition === 'Partly Cloudy' && '⛅'}
                {condition === 'Snowy' && '❄️'}
                {condition === 'Foggy' && '🌫️'}
                {!['Sunny', 'Cloudy', 'Rainy', 'Partly Cloudy', 'Snowy', 'Foggy'].includes(condition) && '🌤️'}
              </Text>
            </Stack>

            {/* Temperature + Unit */}
            <Stack direction="horizontal" gap={0} align="start">
              <Text
                size="4xl"
                weight="bold"
                color="var(--ggui-color-primary-600, #0284c7)"
              >
                {temperature}
              </Text>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
                °{unit}
              </Text>
            </Stack>
          </Stack>
        </Stack>

        {/* DIVIDER */}
        <Divider
          orientation="horizontal"
          margin={0}
          color="var(--ggui-color-outline, #e5e7eb)"
        />

        {/* METRICS: Humidity & Wind Speed */}
        <Stack direction="horizontal" gap={32} align="start">
          {/* Humidity */}
          <Box>
            <Stack direction="vertical" gap={4}>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #374151)">
                Humidity
              </Text>
              <Text
                variant="body"
                weight="bold"
                color="var(--ggui-color-onSurface, #111827)"
              >
                {humidity}%
              </Text>
            </Stack>
          </Box>

          {/* Wind Speed */}
          <Box>
            <Stack direction="vertical" gap={4}>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #374151)">
                Wind Speed
              </Text>
              <Text
                variant="body"
                weight="bold"
                color="var(--ggui-color-onSurface, #111827)"
              >
                {windSpeed} km/h
              </Text>
            </Stack>
          </Box>
        </Stack>

        {/* DIVIDER */}
        <Divider
          orientation="horizontal"
          margin={0}
          color="var(--ggui-color-outline, #e5e7eb)"
        />

        {/* FORECAST STRIP: 5-Day Forecast */}
        {forecast && forecast.length > 0 && (
          <Stack direction="horizontal" gap={8} wrap={true} align="center">
            {forecast.map((item, index) => (
              <Box
                key={index}
                padding={12}
                background="var(--ggui-color-primary-50, #f0f9ff)"
                borderRadius="var(--ggui-shape-radius-md, 8px)"
              >
                <Stack direction="vertical" gap={4} align="center">
                  {/* Day Name */}
                  {item.day && (
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #374151)">
                      {item.day}
                    </Text>
                  )}

                  {/* Weather Icon */}
                  {item.icon && (
                    <Text size="xl" color="currentColor">
                      {item.icon}
                    </Text>
                  )}

                  {/* High/Low Temps */}
                  {item.high !== undefined && item.low !== undefined && (
                    <Text
                      variant="bodySmall"
                      color="var(--ggui-color-onSurfaceVariant, #4b5563)"
                    >
                      {item.high}° / {item.low}°
                    </Text>
                  )}
                </Stack>
              </Box>
            ))}
          </Stack>
        )}
      </Stack>
    </Card>
  );
}
